parameters.jsCode:
const event = $input.first().json;
const detail = event.detail || event;

const exfilTypes = {
  'Exfiltration:S3/ObjectRead.Unusual': { target: 's3', severity: 'SEV1', pci: true },
  'Exfiltration:S3/AnomalousBehavior': { target: 's3', severity: 'SEV1', pci: true },
  'UnauthorizedAccess:EC2/TorIPCaller': { target: 'ec2', severity: 'SEV2', pci: false },
  'Discovery:S3/AnomalousBehavior': { target: 's3', severity: 'SEV2', pci: false },
  'Exfiltration:Runtime/NetworkConnection': { target: 'runtime', severity: 'SEV1', pci: true }
};

const findingType = detail.type || 'Unknown';
const context = exfilTypes[findingType] || { target: 'unknown', severity: 'SEV2', pci: false };

const resource = detail.resource || {};
const s3 = resource.s3BucketDetails?.[0] || {};
const instance = resource.instanceDetails || {};
const network = detail.service?.action?.networkConnectionAction || {};

return [{
  json: {
    incidentId: 'EXFIL-' + Date.now().toString(36).toUpperCase(),
    findingId: detail.id,
    findingType,
    exfilTarget: context.target,
    severity: context.severity,
    pciScope: context.pci,
    accountId: detail.accountId,
    region: detail.region || 'eu-central-1',
    s3BucketName: s3.name || 'N/A',
    s3BucketOwner: s3.owner?.id || 'N/A',
    instanceId: instance.instanceId || 'N/A',
    instanceType: instance.instanceType || 'N/A',
    destinationIp: network.remoteIpDetails?.ipAddressV4 || 'N/A',
    destinationPort: network.remotePortDetails?.port || 'N/A',
    destinationCountry: network.remoteIpDetails?.country?.countryName || 'N/A',
    transferBytes: detail.service?.additionalInfo?.transferredBytes || 0,
    timestamp: detail.updatedAt || new Date().toISOString(),
    gdprNotificationRequired: context.pci,
    notificationDeadlineHours: context.pci ? 72 : null
  }
}];

